import json
import sys
from llvmlite import ir

# 导入用户代码（假设用户函数在 solution 模块中）
from solution import translate_expr

def run_test(expr, expected_substr):
    try:
        module = ir.Module(name="test")
        func_type = ir.FunctionType(ir.IntType(64), [])
        func = ir.Function(module, func_type, name="test_func")
        block = func.append_basic_block(name="entry")
        builder = ir.IRBuilder(block)
        # 预设环境，包含变量 x 和 y
        x_val = ir.Constant(ir.IntType(64), 42)
        y_val = ir.Constant(ir.IntType(64), 77)
        env = {"x": x_val, "y": y_val}

        result = translate_expr(expr, builder, env)
        builder.ret(result)

        ir_text = str(module)
        if expected_substr in ir_text:
            return {"name": expected_substr, "passed": True, "message": "", "expected": expected_substr, "actual": ir_text[:100]}
        else:
            return {"name": expected_substr, "passed": False, "message": f"IR text does not contain '{expected_substr}'", "expected": expected_substr, "actual": ir_text[:200]}
    except Exception as e:
        return {"name": expected_substr, "passed": False, "message": str(e), "expected": expected_substr, "actual": "ERROR"}

# 测试用例列表
test_cases = [
    (3, "i64 3"),
    ("x", "%x"),
    (["+", 3, 4], "add i64 3, 4"),
    (["-", 10, ["+", 2, 3]], "sub i64 10, %addtmp"),
    (["*", 6, 7], "mul i64 6, 7"),
    (["/", 9, 3], "sdiv i64 9, 3")
]

for expr, expected in test_cases:
    result = run_test(expr, expected)
    print(json.dumps(result))
